import redis
import json
import os
from typing import Optional, Dict, Any
from datetime import timedelta

class RedisCache:
    def __init__(self, redis_nodes: list, password: str = None):
        self.redis_nodes = redis_nodes
        self.password = password
        self.redis_connections = []
        self._connect_to_cluster()
    
    def _connect_to_cluster(self):
        for node in self.redis_nodes:
            try:
                connection = redis.Redis(
                    host=node['host'],
                    port=node['port'],
                    password=self.password,
                    decode_responses=True,
                    socket_timeout=5,
                    socket_connect_timeout=5,
                    retry_on_timeout=True,
                    health_check_interval=30
                )
                connection.ping()
                self.redis_connections.append(connection)
            except Exception as e:
                print(f"Failed to connect to Redis node {node}: {e}")
    
    def set_user_data(self, user_id: str, data: Dict[str, Any], ttl_minutes: int = 30) -> bool:
        try:
            key = f"user:{user_id}"
            data_json = json.dumps(data)
            ttl_seconds = ttl_minutes * 60
            
            if self.redis_connections:
                connection = self.redis_connections[0]  # Use first connection
                connection.setex(key, ttl_seconds, data_json)
                return True
            return False
        except Exception as e:
            print(f"Error setting user data: {e}")
            return False
    
    def get_user_data(self, user_id: str) -> Optional[Dict[str, Any]]:
        try:
            key = f"user:{user_id}"
            if self.redis_connections:
                connection = self.redis_connections[0]
                data = connection.get(key)
                if data:
                    return json.loads(data)
            return None
        except Exception as e:
            print(f"Error getting user data: {e}")
            return None
    
    def delete_user_data(self, user_id: str) -> bool:
        try:
            key = f"user:{user_id}"
            if self.redis_connections:
                connection = self.redis_connections[0]
                deleted = connection.delete(key)
                return deleted > 0
            return False
        except Exception as e:
            print(f"Error deleting user data: {e}")
            return False
    
    def set_session_token(self, session_id: str, token: str, ttl_minutes: int = 60) -> bool:
        try:
            key = f"session:{session_id}"
            ttl_seconds = ttl_minutes * 60
            
            if self.redis_connections:
                connection = self.redis_connections[0]
                connection.setex(key, ttl_seconds, token)
                return True
            return False
        except Exception as e:
            print(f"Error setting session token: {e}")
            return False
    
    def get_session_token(self, session_id: str) -> Optional[str]:
        try:
            key = f"session:{session_id}"
            if self.redis_connections:
                connection = self.redis_connections[0]
                return connection.get(key)
            return None
        except Exception as e:
            print(f"Error getting session token: {e}")
            return None
    
    def set_api_key(self, user_id: str, api_key: str, ttl_minutes: int = 43200) -> bool:
        try:
            key = f"api_key:{user_id}"
            ttl_seconds = ttl_minutes * 60
            
            if self.redis_connections:
                connection = self.redis_connections[0]
                connection.setex(key, ttl_seconds, api_key)
                return True
            return False
        except Exception as e:
            print(f"Error setting API key: {e}")
            return False
    
    def get_api_key(self, user_id: str) -> Optional[str]:
        try:
            key = f"api_key:{user_id}"
            if self.redis_connections:
                connection = self.redis_connections[0]
                return connection.get(key)
            return None
        except Exception as e:
            print(f"Error getting API key: {e}")
            return None

